let currentLang = localStorage.getItem('siteLang') || 'ru';

function setLanguage(lang) {
  currentLang = lang;
  localStorage.setItem('siteLang', lang);
  document.documentElement.lang = lang;
  applyTranslations();
  updateLangSwitcher();
}

function applyTranslations() {
  const t = translations[currentLang];
  if (!t) return;
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (t[key] !== undefined) {
      if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
        if (el.placeholder) el.placeholder = t[key];
      } else if (el.tagName === 'OPTION') {
        el.textContent = t[key];
      } else {
        el.textContent = t[key];
      }
    }
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.dataset.i18nPlaceholder;
    if (t[key] !== undefined) el.placeholder = t[key];
  });
  document.querySelectorAll('[data-i18n-aria]').forEach(el => {
    const key = el.dataset.i18nAria;
    if (t[key] !== undefined) el.setAttribute('aria-label', t[key]);
  });
}

function updateLangSwitcher() {
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.lang === currentLang);
  });
}

function initI18n() {
  applyTranslations();
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const lang = btn.dataset.lang;
      if (lang && lang !== currentLang) setLanguage(lang);
    });
  });
}

// ========================================
// PRELOADER
// ========================================
document.body.classList.add('loading');
const preloader = document.getElementById('preloader');
const preloaderBar = document.getElementById('preloaderBar');
const preloaderPercent = document.getElementById('preloaderPercent');
const preloaderText = document.getElementById('preloaderText');

const phrases = [
  'Укладываем фундамент','Возводим каркас','Проектируем пространство',
  'Инвестируем в детали','Финишная отделка','Запускаем системы',
  'Вводим объект','Добро пожаловать'
];
const MIN_DURATION = 5200;
const PHRASE_DURATION = MIN_DURATION / phrases.length;
let progress = 0, resourcesLoaded = false, startTime = performance.now(), animationFrame = null, currentPhraseIndex = -1;

function animateLoader() {
  const elapsed = performance.now() - startTime;
  const timeProgress = Math.min(elapsed / MIN_DURATION, 1);
  progress = Math.round(timeProgress * 100);
  preloaderBar.style.width = progress + '%';
  preloaderPercent.textContent = progress + '%';
  const newPhraseIndex = Math.min(Math.floor(elapsed / PHRASE_DURATION), phrases.length - 1);
  if (newPhraseIndex !== currentPhraseIndex) {
    currentPhraseIndex = newPhraseIndex;
    preloaderText.textContent = phrases[currentPhraseIndex];
  }
  if (timeProgress < 1 || !resourcesLoaded) {
    animationFrame = requestAnimationFrame(animateLoader);
  } else {
    finishLoader();
  }
}

function finishLoader() {
  cancelAnimationFrame(animationFrame);
  progress = 100;
  preloaderBar.style.width = '100%';
  preloaderPercent.textContent = '100%';
  preloaderText.textContent = phrases[phrases.length - 1];
  setTimeout(() => {
    preloader.classList.add('hidden');
    document.body.classList.remove('loading');
    initApp();
  }, 900);
}

let pendingResources = 0;
function trackResource() { pendingResources++; }
function resourceDone() { pendingResources--; checkResources(); }
function checkResources() { if (pendingResources <= 0) resourcesLoaded = true; }

document.querySelectorAll('img').forEach(img => {
  if (!img.complete) { trackResource(); img.addEventListener('load', resourceDone); img.addEventListener('error', resourceDone); }
});

const bgEls = document.querySelectorAll('[style*="background-image"]');
bgEls.forEach(el => {
  const style = window.getComputedStyle(el);
  const bg = style.backgroundImage;
  if (bg && bg !== 'none') {
    const m = bg.match(/url\(["']?([^"')]+)["']?\)/);
    if (m) { trackResource(); const img = new Image(); img.onload = resourceDone; img.onerror = resourceDone; img.src = m[1]; }
  }
});

window.addEventListener('load', () => { resourcesLoaded = true; });
setTimeout(() => { resourcesLoaded = true; }, 6000);
animationFrame = requestAnimationFrame(animateLoader);

